import { parseServerFormsValue } from '../../models/server/forms/value.js';
import { serverSubmitItemActionRequestSchema } from '../../schemas/server/items/submit.js';
import { parse } from '../../utils/json.js';
import { handleError } from '../error.js';
export const createServerSubmitItemActionRouteHandler = (group) => async ({ req, res, localize, ctx }) => {
    if (!group.submitActionHandler) {
        res.status(404).end();
        return;
    }
    const itemName = req.params.itemName;
    if (!itemName) {
        res.status(400).end();
        return;
    }
    const body = req.body;
    if (!(body instanceof Buffer)) {
        res.status(400).end();
        return;
    }
    const request = parse(body, serverSubmitItemActionRequestSchema);
    if (!request) {
        res.status(400).end();
        return;
    }
    const value = parseServerFormsValue(Object.fromEntries(new URLSearchParams(request.values)), group.actions);
    if (!value) {
        res.status(400).end();
        return;
    }
    const response = await group.submitActionHandler({ ...ctx, itemName, value });
    if (handleError(response, res, localize))
        return;
    res.json(response);
};
